#include <algorithm>

int maxDistance(vector<int>& nums1, vector<int>& nums2) {
    int i=nums1.size()-1;
    int j= nums2.size()-1;
    int maxD = 0;
    while(i>=0 && j>=0){
        if(nums1[i] <= nums2[j]){
            maxD = max(maxD, j-i);
            --i;
        }
        else
            --j;
    }
    return maxD;
}

int binary_search(vector<int> &arr,int j, int search_key)
{
    int i = 0, ans = -1;
    j = min((int)arr.size()-1, j);

    while (i <= j)
    {
        int mid = i + (j - i) / 2;
        if (arr[mid] <= search_key){
            ans = mid;
            j = mid - 1;
        }
        else
            i = mid + 1;
    }
    return ans;
}

int maxDistance1(vector<int>& nums1, vector<int>& nums2) {
        int maxD = 0;
        for(int j = 0; j<nums2.size(); ++j){
            int i = binary_search(nums1, j, nums2[j]);
            if(i != -1 && i<=j)
                maxD = max(maxD, j - i);
        }
        return maxD;
    }

